#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#define MAX_N 500
#define MAX_M 500
#define MAX_K 1000000000

// Structure to represent a gnome
typedef struct {
    int id;
    int* friends;
    int num_friends;
} Gnome;

// Function to perform BFS
void bfs(Gnome* gnomes, int num_gnomes, int source, int k, int* result) {
    bool* visited = (bool*) calloc(num_gnomes, sizeof(bool));
    int* queue = (int*) malloc(num_gnomes * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = source;
    visited[source] = true;
    for (int i = 0; i < k; i++) {
        int temp_rear = rear;
        for (int j = front; j < temp_rear; j++) {
            for (int l = 0; l < gnomes[queue[j]].num_friends; l++) {
                if (!visited[gnomes[queue[j]].friends[l]]) {
                    queue[rear++] = gnomes[queue[j]].friends[l];
                    visited[queue[rear - 1]] = true;
                }
            }
        }
        front = temp_rear;
    }
    *result = rear - front;
    for (int i = front; i < rear; i++) {
        printf("%d ", queue[i] + 1);
    }
    printf("\n");
    free(queue);
    free(visited);
}

int main() {
    int num_gnomes;
    scanf("%d", &num_gnomes);
    Gnome* gnomes = (Gnome*) malloc(num_gnomes * sizeof(Gnome));
    for (int i = 0; i < num_gnomes; i++) {
        gnomes[i].id = i;
        gnomes[i].friends = (int*) malloc(num_gnomes * sizeof(int));
        gnomes[i].num_friends = 0;
        for (int j = 0; j < num_gnomes; j++) {
            int temp;
            scanf("%d", &temp);
            if (temp == 1) {
                gnomes[i].friends[gnomes[i].num_friends++] = j;
            }
        }
    }
    int num_queries;
    scanf("%d", &num_queries);
    for (int i = 0; i < num_queries; i++) {
        int k, source;
        scanf("%d %d", &k, &source);
        source--;
        int result;
        bfs(gnomes, num_gnomes, source, k, &result);
        printf("%d\n", result);
    }
    for (int i = 0; i < num_gnomes; i++) {
        free(gnomes[i].friends);
    }
    free(gnomes);
    return 0;
}

