#include <iostream>
#include <vector>
#include <queue>
#include <unordered_set>
using namespace std;

// Structure to represent a gnome
struct Gnome {
    int id;
    vector<int> friends;
};

// Function to perform BFS
void bfs(vector<Gnome>& gnomes, int source, int k, vector<int>& result) {
    unordered_set<int> visited;
    queue<int> q;
    q.push(source);
    visited.insert(source);
    for (int i = 0; i < k; i++) {
        int size = q.size();
        for (int j = 0; j < size; j++) {
            int current = q.front();
            q.pop();
            for (int l = 0; l < gnomes[current].friends.size(); l++) {
                if (visited.find(gnomes[current].friends[l]) == visited.end()) {
                    q.push(gnomes[current].friends[l]);
                    visited.insert(gnomes[current].friends[l]);
                }
            }
        }
    }
    result.clear();
    for (auto& gnome : visited) {
        result.push_back(gnome);
    }
}

int main() {
    int num_gnomes;
    cin >> num_gnomes;
    vector<Gnome> gnomes(num_gnomes);
    for (int i = 0; i < num_gnomes; i++) {
        gnomes[i].id = i;
        for (int j = 0; j < num_gnomes; j++) {
            int temp;
            cin >> temp;
            if (temp == 1) {
                gnomes[i].friends.push_back(j);
            }
        }
    }
    int num_queries;
    cin >> num_queries;
    for (int i = 0; i < num_queries; i++) {
        int k, source;
        cin >> k >> source;
        source--;
        vector<int> result;
        bfs(gnomes, source, k, result);
        cout << result.size() << endl;
        for (auto& gnome : result) {
            cout << gnome + 1 << " ";
        }
        cout << endl;
    }
    return 0;
}

