import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;
import java.util.HashSet;
public class Main {
    // Structure to represent a gnome
    static class Gnome {
        int id;
        int[] friends;
        int num_friends;
        Gnome(int id, int[] friends, int num_friends) {
            this.id = id;
            this.friends = friends;
            this.num_friends = num_friends;
        }
    }

    // Function to perform BFS
    public static void bfs(Gnome[] gnomes, int source, int k, int[] result) {
        boolean[] visited = new boolean[gnomes.length];
        Queue<Integer> q = new LinkedList<>();
        q.add(source);
        visited[source] = true;
        for (int i = 0; i < k; i++) {
            int size = q.size();
            for (int j = 0; j < size; j++) {
                int current = q.poll();
                for (int l = 0; l < gnomes[current].num_friends; l++) {
                    if (!visited[gnomes[current].friends[l]]) {
                        q.add(gnomes[current].friends[l]);
                        visited[gnomes[current].friends[l]] = true;
                    }
                }
            }
        }
        int count = 0;
        for (int i = 0; i < visited.length; i++) {
            if (visited[i]) {
                result[count++] = i;
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int num_gnomes = sc.nextInt();
        Gnome[] gnomes = new Gnome[num_gnomes];
        for (int i = 0; i < num_gnomes; i++) {
            gnomes[i] = new Gnome(i, new int[num_gnomes], 0);
            for (int j = 0; j < num_gnomes; j++) {
                int temp = sc.nextInt();
                if (temp == 1) {
                    gnomes[i].friends[gnomes[i].num_friends++] = j;
                }
            }
        }
        int num_queries = sc.nextInt();
        for (int i = 0; i < num_queries; i++) {
            int k = sc.nextInt();
            int source = sc.nextInt() - 1;
            int[] result = new int[gnomes.length];
            bfs(gnomes, source, k, result);
            int count = 0;
            for (int j = 0; j < result.length; j++) {
                if (result[j] != 0) {
                    count++;
                }
            }
            System.out.println(count);
            for (int j = 0; j < result.length; j++) {
                if (result[j] != 0) {
                    System.out.print((result[j] + 1) + " ");
                }
            }
            System.out.println();
        }
    }
}

