from collections import deque

# Structure to represent a gnome
class Gnome:
    def __init__(self, id, friends):
        self.id = id
        self.friends = friends

# Function to perform BFS
def bfs(gnomes, source, k):
    visited = set()
    q = deque([source])
    visited.add(source)
    for _ in range(k):
        for _ in range(len(q)):
            current = q.popleft()
            for friend in gnomes[current].friends:
                if friend not in visited:
                    q.append(friend)
                    visited.add(friend)
    return list(visited)

# Main function
def main():
    num_gnomes = int(input())
    gnomes = [None] * num_gnomes
    for i in range(num_gnomes):
        friends = [j for j, x in enumerate(map(int, input().split())) if x == 1]
        gnomes[i] = Gnome(i, friends)
    num_queries = int(input())
    for _ in range(num_queries):
        k, source = map(int, input().split())
        source -= 1
        result = bfs(gnomes, source, k)
        print(len(result))
        print(' '.join(map(lambda x: str(x + 1), result)))

if __name__ == '__main__':
    main()

